using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns JsonTypeInfo<Person> directly, no cast needed
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> resolved: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {info!.Type.Name}");
}

// Now demonstrate the "not available" path using a source-gen context that
// only knows about Person — querying an unregistered type won't throw.
var limited = new JsonSerializerOptions { TypeInfoResolver = PersonContext.Default };

if (limited.TryGetTypeInfo<UnregisteredType>(out JsonTypeInfo<UnregisteredType>? missing))
{
    Console.WriteLine($"Unexpected: resolved {missing!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<UnregisteredType> returned false — no exception thrown.");
}

// Types
public record Person(string Name, int Age);
public class UnregisteredType { public int X { get; set; } }

// Minimal source-gen context that only resolves Person
[JsonSerializable(typeof(Person))]
public partial class PersonContext : JsonSerializerContext;
EOF

